<script setup>import {onMounted,ref} from 'vue';import {useRoute} from 'vue-router';import {getMemberRepair} from '../api/repairApi';const route=useRoute(),item=ref(null),loading=ref(true),error=ref('');const money=v=>v==null?'尚未報價':new Intl.NumberFormat('zh-TW',{style:'currency',currency:'TWD',maximumFractionDigits:0}).format(v);onMounted(async()=>{try{item.value=await getMemberRepair(route.params.id)}catch(e){error.value=e.message}finally{loading.value=false}})</script>
<template><section class="member-section"><RouterLink class="back-link" to="/member/repairs">← 返回我的維修</RouterLink><p v-if="error" class="alert alert-error">{{error}}</p><div v-if="loading" class="loading-state">正在載入案件…</div><template v-else-if="item"><div class="page-heading"><div><span class="eyebrow">REPAIR DETAIL</span><h1>RP-{{item.id}}</h1><p>{{item.deviceBrand}} {{item.deviceModel}}</p></div><span class="badge">{{item.repairStatus}}</span></div><div class="detail-cards"><section class="card"><h2>故障資訊</h2><dl><dt>IMEI</dt><dd>{{item.imei||'未提供'}}</dd><dt>問題描述</dt><dd>{{item.problemDescription}}</dd><dt>收件／預約日期</dt><dd>{{item.receivedDate}}</dd></dl></section><section class="card"><h2>維修資訊</h2><dl><dt>預估費用</dt><dd>{{money(item.estimatedCost)}}</dd><dt>最終費用</dt><dd>{{money(item.finalCost)}}</dd><dt>技師</dt><dd>{{item.technicianName||'尚未指派'}}</dd><dt>服務說明</dt><dd>{{item.repairNotes||'目前沒有補充說明'}}</dd></dl></section></div></template></section></template>
